INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$Is there a free trial?$q$, $q$Yes, Hypotenuse AI offers a free trial with no credit card required.$q$, 1);
