INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cbb957cc-8de9-4968-928e-1b42cfb27349', $q$who-its-for$q$, $q$Who Hypotenuse AI is for$q$, 2, ARRAY[$q$The platform targets enterprise ecommerce teams and larger retailers managing large or multi-channel product catalogs, rather than small single-store merchants.$q$]::text[], 1);
