INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$who-its-for$q$, $q$Who ParagraphAI is for$q$, 2, ARRAY[$q$ParagraphAI targets students, professionals, ESL learners, and people with dyslexia who want writing help built into their existing keyboard and browser, with an Enterprise tier for teams needing brand voice controls.$q$]::text[], 1);
