INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Multi-seat collaboration only becomes available starting on the Pro plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Extra campaigns beyond a plan's monthly limit cost $10 each$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Is there a free trial of Simplified?$q$, $q$Yes, Simplified offers a trial with full Starter-plan access (5 campaigns, 100K AI words, 100 AI designs) with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$What does the Riley AI agent do?$q$, $q$Riley plans, creates, and publishes marketing campaigns end-to-end, adjusting output based on approvals and feedback.$q$, 1);
