INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Does Simplified offer an API?$q$, $q$Yes, it offers an MCP server, CLI, REST API/webhooks, and OAuth2 for developers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$What happens if I use more campaigns than my plan allows?$q$, $q$Additional campaigns can be purchased for $10 each on any plan.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Lean team campaign automation$q$, $q$Founders and small marketing teams let Riley plan and publish full campaigns without a large team.$q$, $q$Founders and lean marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Agency client management$q$, $q$Agencies manage brand kits and approvals for multiple clients from one workspace.$q$, $q$Agency professionals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Custom AI agent workflows$q$, $q$Technical teams connect their own AI agents (e.g. Claude, Codex, Cursor) via Simplified's API and MCP server.$q$, $q$Teams building custom AI agents$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Simplified Starter$q$, $q$$59/month billed monthly, $79/month billed annually$q$, NULL, $q$["5 campaigns/month","100K AI words","100 AI designs","50 AI videos","7 social accounts","5 GB storage","1 brand kit"]$q$::jsonb, 0);
