INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$Simplified Business$q$, $q$$239/month billed monthly, $199/month billed annually$q$, NULL, $q$["40 campaigns/month","7 seats","Unlimited AI words/designs/videos","30 social accounts","100 GB storage","Unlimited brand kits","Bulk scheduling","External client approval","Advanced analytics"]$q$::jsonb, 2);
