INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6aee23c-70db-420b-83e9-7069be0216f1', $q$who-its-for$q$, $q$Who Simplified is for$q$, 2, ARRAY[$q$Simplified serves founders and lean marketing teams, agencies managing multiple clients, and technical teams that want to connect their own AI agents to a marketing workflow.$q$]::text[], 1);
