INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Is there a free plan for Jenni AI?$q$, $q$Yes, Jenni offers a free plan with 10 AI autocompletes per day, 10 PDF uploads, and limited AI edits, chat, and reviews, with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$What citation styles does Jenni support?$q$, $q$Jenni supports over 10,000 citation styles, including APA 7th edition, Chicago, and Harvard.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Can I import my existing reference library?$q$, $q$Yes, Jenni lets you import references from Zotero or Mendeley, or search over 200 million papers directly.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$How much does Jenni AI cost?$q$, $q$Jenni has a free plan, a Plus plan at $12/month, and a Pro plan at $29/month, each billed monthly with annual discounts available.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Does Jenni check facts in my writing?$q$, $q$Yes, the Reviews feature analyzes claims in a draft and flags statements that are unverified or contradicted by cited sources.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Writing cited research papers$q$, $q$Graduate students and PhD candidates draft papers with AI autocomplete that automatically cites uploaded source material.$q$, $q$Graduate students & PhD candidates$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Literature review at scale$q$, $q$Research labs use Research Chat to query an entire library of uploaded papers and get sourced answers.$q$, $q$Research labs$q$, 1);
