INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["10 AI Autocompletes/day","10 PDF uploads","3 AI Edits","5 AI Chat messages","3 Reviews","10,000+ citation styles","Unlimited citations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Plus$q$, $q$$12/month$q$, $q$monthly$q$, $q$["5,000 Autocompletes/month","Unlimited PDF uploads","500 AI Edits/month","500 AI Chat/month","10 Reviews/month","Full document export","Live chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$Pro$q$, $q$$29/month$q$, $q$monthly$q$, $q$["Unlimited AI Autocomplete","Unlimited PDF uploads","Unlimited AI Edits","Unlimited AI Chat","Unlimited Reviews","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$overview$q$, $q$What is Jenni AI?$q$, 2, ARRAY[$q$Jenni AI is an AI writing assistant built for academic and research writing. It generates AI autocomplete suggestions grounded in a user's uploaded papers, and links every AI-assisted claim back to the exact page and paragraph of its source.$q$, $q$Beyond drafting, Jenni supports reference management with imports from Zotero and Mendeley, a search index of over 200 million papers, and formatting across more than 10,000 citation styles.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71403b09-3361-45de-9911-89b692d11395', $q$who-its-for$q$, $q$Who Jenni AI is for$q$, 2, ARRAY[$q$Jenni is built for graduate students, PhD candidates, university researchers, and professionals in fields like pharma and policy analysis who need writing that is both fast and fully cited to source material.$q$]::text[], 1);
