INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('20246395-4c99-4ebe-aa25-c4a917239735', $q$Does Fliki offer voice cloning?$q$, $q$Yes, paid plans include voice cloning by recording a voice sample.$q$, 3);
