INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$How long is my data stored?$q$, $q$Files are retained for 7 days and then permanently deleted; data is stored in the EU and Cleanvoice is ISO 27001 certified.$q$, 4);
