INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$overview$q$, $q$What is Cleanvoice?$q$, 2, ARRAY[$q$Cleanvoice is an AI-powered audio and video editing tool built for podcast production. It automatically removes filler words, background noise, mouth sounds, and long silences from recordings, and adds transcription and episode summaries.$q$, $q$The service is used by more than 15,000 podcasters, and its API is integrated into more than 30 other products for automated post-production.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$who-its-for$q$, $q$Who Cleanvoice is for$q$, 2, ARRAY[$q$Cleanvoice suits podcasters, audio engineers, and video editors who want to cut manual cleanup time, as well as media agencies and platforms that use its API to automate editing for their own users.$q$]::text[], 1);
