INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Custom vocabulary transcription$q$, $q$Improves transcript accuracy with up to 750 custom terms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Action item tracking$q$, $q$Automatically organizes and tracks meeting action items.$q$, 4);
