INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Is Krisp free?$q$, $q$Yes, Krisp offers a free tier plus a 7-day free trial of its paid Meeting AI features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$How much does Krisp cost?$q$, $q$The Core plan is $16/user/month ($8/month billed annually), and Advanced is $30/user/month ($15/month billed annually); Enterprise pricing is custom.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$What conferencing apps does Krisp work with?$q$, $q$It works at the audio level with apps including Zoom, Google Meet, Microsoft Teams, Webex, and Discord calls.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Does Krisp support languages other than English?$q$, $q$Yes, transcripts and meeting summaries are available in 16 languages, including Spanish, French, German, and Korean.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Where is Krisp based?$q$, $q$Krisp's headquarters is in Berkeley, California.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Noise-free remote calls$q$, $q$Remove background noise and echo from any calling app during meetings or customer calls.$q$, $q$Remote and hybrid teams$q$, 0);
