INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Call center audio quality$q$, $q$Apply voice isolation and after-call summaries to support agent calls.$q$, $q$Call centers and BPOs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Core$q$, $q$$16/user/month ($8/month billed annually)$q$, $q$monthly$q$, $q$["Unlimited AI note-taker","Noise cancellation","Mobile app","1 hr/day accent conversion","10 GB storage"]$q$::jsonb, 0);
