INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["SSO/SCIM","On-device transcription","Dedicated account manager","HIPAA compliance","Unlimited storage"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$overview$q$, $q$What is Krisp?$q$, 2, ARRAY[$q$Krisp is an AI voice and meeting assistant that cancels background noise, echo, and cross-talk on any calling app, and generates meeting transcripts, summaries, and action items.$q$, $q$Beyond individual meetings, Krisp also offers a Call Center AI product with voice isolation and after-call summaries, plus a developer API for noise cancellation and accent conversion.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$who-its-for$q$, $q$Who Krisp is for$q$, 2, ARRAY[$q$Krisp is built for remote workers and sales/support teams who want cleaner call audio, as well as call centers and BPOs that need noise cancellation and analytics across many agents.$q$]::text[], 1);
