INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Noise & reverb reduction$q$, $q$Reduces background noise and room reverb in recordings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Filler word & silence removal$q$, $q$Automatically cuts filler words, coughs, and long silences.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Multitrack processing$q$, $q$Applies ducking and noise gates across multiple speaker tracks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Loudness normalization$q$, $q$Normalizes output to broadcast and streaming loudness specifications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Speech-to-text & show notes$q$, $q$Generates transcripts and automatic show notes on paid plans.$q$, 5);
