INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Publishing integrations$q$, $q$Connects to YouTube, Libsyn, Podbean, SoundCloud, plus Zapier, API, and CLI access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Free tier processes 2 hours of audio per month at no cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$One-time credit packages don't expire, useful for infrequent use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Accessible via web app, API, CLI, and Zapier for automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Cites large publishers such as BBC Radio, Buzzsprout, and iHeartRadio as users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Free tier adds an Auphonic watermark jingle and excludes speech recognition/show notes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Free tier limits multitrack productions to under 20 minutes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Subscription and credit prices are not shown as static figures on the pricing page (rendered dynamically by currency/region)$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Is Auphonic free?$q$, $q$Yes, a free tier processes 2 hours of audio per month, though it adds an Auphonic jingle and excludes speech recognition and show notes.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$What does Auphonic do?$q$, $q$It automatically levels, cleans, and normalizes podcast and video audio, and can generate transcripts and show notes.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Can I buy audio processing credits without a subscription?$q$, $q$Yes, one-time credit packages are available from 5 hours up to 3000+ hours, and unused credits don't expire.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Does Auphonic support video?$q$, $q$Yes, it can process video files and generate chapters and audiograms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$What speech recognition does Auphonic use?$q$, $q$Paid plans include multilingual speech-to-text, and the site references OpenAI's Whisper model.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Podcast audio cleanup$q$, $q$Automatically level, denoise, and normalize episode audio before publishing.$q$, $q$Podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Multitrack interview processing$q$, $q$Apply ducking and noise gates across multiple speaker tracks in one pass.$q$, $q$Audio producers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$Automated show notes$q$, $q$Generate transcripts and show notes automatically alongside audio processing.$q$, $q$Podcast production teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$overview$q$, $q$What is Auphonic?$q$, 2, ARRAY[$q$Auphonic is a web-based AI audio post-production service that automatically levels, cleans, and normalizes speech and music. It handles noise and reverb reduction, filler-word and silence removal, and loudness normalization to broadcast standards.$q$, $q$The service also offers multilingual speech-to-text, automatic show notes, and video support with chapters and audiograms, accessible via its web app, API, CLI, or Zapier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', $q$who-its-for$q$, $q$Who Auphonic is for$q$, 2, ARRAY[$q$Auphonic is aimed at podcasters, audio engineers, and video creators who want consistent, professional-sounding audio without manually mixing every episode.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
