INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4dd68fbf-0f44-4e17-ac9c-f3c2cd8a74b6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
