INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Rapid Clone$q$, $q$Creates a working voice clone in under 1 minute from about 10 seconds of audio.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Professional Clone$q$, $q$Higher-fidelity voice clone trained from 10-25+ minutes of audio, with a fuller emotional range.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Voice Design$q$, $q$Generates new synthetic voice candidates from a text description of desired characteristics.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Zero-shot multilingual cloning$q$, $q$The Chatterbox model clones voices across 23 languages without separate training runs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Detect$q$, $q$Multimodal deepfake detection for audio, image, and video content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Verify$q$, $q$Invisible watermarking for tracking audio/image/video content provenance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Resemble Meetings$q$, $q$A bot that can be invited into live calls to flag synthetic audio in real time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Developer access$q$, $q$REST API, Python and Node.js SDKs, and self-hosted Docker/Kubernetes deployment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Combines voice generation with deepfake detection and watermarking in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Pay-as-you-go Flex plan requires no upfront commitment and credits don't expire$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Supports on-premises/self-hosted deployment for security-sensitive customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$SOC2 Type II, GDPR, and HIPAA compliance claimed for enterprise plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$No published flat monthly pricing; usage is billed per second/search and Enterprise requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Founding year and headquarters are not disclosed on the site$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Custom model training and SSO/SAML are reserved for the Enterprise tier$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$What does Resemble AI do?$q$, $q$It provides AI voice cloning and text-to-speech generation, plus deepfake detection (Detect) and content watermarking (Verify) for audio, image, and video.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$How much does Resemble AI cost?$q$, $q$The Flex plan starts at $0 and bills usage per second/search (e.g., $0.04/second for audio detection), while Enterprise plans use custom volume pricing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$How many languages does voice cloning support?$q$, $q$The Chatterbox model supports zero-shot voice cloning across 23 languages.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Can Resemble AI detect AI-generated voices in real time?$q$, $q$Yes, Resemble Meetings lets users invite a detection bot into live calls to flag synthetic audio.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Is on-premises deployment available?$q$, $q$Yes, Enterprise plans support on-premises or self-hosted deployment via Docker/Kubernetes.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Branded voice cloning$q$, $q$Create a custom cloned voice for products, IVR, or content from a short audio sample.$q$, $q$Product and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Synthetic media detection$q$, $q$Screen audio, image, or video for AI-generated deepfakes before acting on it.$q$, $q$Finance, telecom, and media companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Live call protection$q$, $q$Monitor meetings in real time for synthetic voice impersonation.$q$, $q$Enterprise security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Flex$q$, $q$$0 to start, pay-as-you-go$q$, NULL, $q$["Credits never expire","Identity, watermarking, and detection models","UI and API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Team seat add-on$q$, $q$$20/month per user$q$, $q$monthly$q$, $q$["Additional scalable team seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Volume discounts","Higher concurrency limits","Custom model training","SSO/SAML","On-premises deployment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$overview$q$, $q$What is Resemble AI?$q$, 2, ARRAY[$q$Resemble AI is a voice AI platform that combines generative voice cloning and text-to-speech with deepfake detection and watermarking. Its Rapid Clone and Professional Clone tools generate custom voices from short audio samples, while Detect and Verify screen and mark synthetic audio, image, and video content.$q$, $q$The company's clients span telecom, finance, media, and public-sector organizations, including Netflix, Paramount, and Deutsche Telekom.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f3d550-5ec1-491d-9aa7-919a574aa346', $q$who-its-for$q$, $q$Who Resemble AI is for$q$, 2, ARRAY[$q$Resemble AI suits enterprises that need both branded voice generation and protection against voice/video deepfakes, such as media companies, call centers, and security teams handling executive-impersonation risk.$q$]::text[], 1);
