INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Does LOVO offer a free trial?$q$, $q$Yes, a 14-day trial of the Pro plan is available with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$How many voices and languages does LOVO support?$q$, $q$LOVO offers over 500 voices across more than 100 languages and accents.$q$, 1);
