INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Where is LOVO based?$q$, $q$LOVO's office is listed at SkyDeck, 2150 Shattuck Ave, Berkeley, California.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Does LOVO have an API?$q$, $q$Yes, an API is available for developers to integrate LOVO's voice generation.$q$, 4);
