INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$overview$q$, $q$What is LOVO?$q$, 2, ARRAY[$q$LOVO is an AI voice generation and video editing platform built around its Genny studio. It provides text-to-speech in 500+ voices across 100+ languages, voice cloning from a short audio sample, and an integrated video editor with auto-generated subtitles.$q$, $q$The platform also includes an AI scriptwriting tool and royalty-free AI image generation, aimed at creators producing marketing, training, and social content.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$who-its-for$q$, $q$Who LOVO is for$q$, 2, ARRAY[$q$LOVO is aimed at marketers, e-learning teams, and content creators who need multilingual voiceovers and quick video editing without hiring voice actors.$q$]::text[], 1);
