INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Is WellSaid free to try?$q$, $q$Yes, a free trial offers 10 minutes of generation and 3 downloaded minutes per month, though without commercial usage rights.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$How much does WellSaid cost?$q$, $q$Starter is $10/month billed annually ($19/month billed monthly); Pro is $33/month billed annually ($49/month monthly); Business and Enterprise are custom/team-priced.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Does WellSaid include commercial usage rights?$q$, $q$Yes, all paid plans include full commercial rights to generated audio.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$What editing tools integrate with WellSaid?$q$, $q$Adobe Express and Adobe Premiere Pro integrations are available, along with a developer API.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Did WellSaid Labs change its domain?$q$, $q$Yes, wellsaidlabs.com now redirects to wellsaid.io, the current site for the same product.$q$, 4);
