INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$overview$q$, $q$What is WellSaid?$q$, 2, ARRAY[$q$WellSaid (formerly WellSaid Labs) is an AI text-to-speech studio offering more than 120 voices built from licensed voice-actor recordings. Its AI Director tool lets users adjust pronunciation, pacing, and tone, and all paid plans include full commercial usage rights.$q$, $q$The company's customers include Microsoft, Adobe, and Amazon, and the platform integrates with Adobe Express and Premiere Pro.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$who-its-for$q$, $q$Who WellSaid is for$q$, 2, ARRAY[$q$WellSaid is aimed at corporate learning and development, marketing, and video production teams that need commercially licensed voiceovers with tone and pacing control.$q$]::text[], 1);
