INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$overview$q$, $q$What is Cognism?$q$, 2, ARRAY[$q$Cognism is a B2B sales intelligence platform that provides phone-verified contact data, intent and hiring/funding signals, and CRM enrichment for revenue teams, with particular strength in European markets.$q$, $q$It also offers a Data-as-a-Service option, delivering verified B2B data via API or batch export, and runs data through an AI-driven fusion engine plus compliance screening (DNC/TPS) before it reaches sales teams.$q$]::text[], 0);
