INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7fc750-3534-46bb-99e5-aed53ba7b5c8', $q$overview$q$, $q$What is ZoomInfo?$q$, 2, ARRAY[$q$ZoomInfo, founded in 2007 (originally as DiscoverOrg and rebranded after acquiring Zoom Information, Inc. in 2019), is a go-to-market platform headquartered in Vancouver, Washington, and publicly traded on the Nasdaq under the ticker GTM.$q$, $q$The platform provides verified B2B contact and company data, buying-intent signals, and add-on modules such as Chorus for conversation intelligence and Copilot for AI-powered prospecting, integrating with CRM and sales engagement tools.$q$]::text[], 0);
