INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cc05431a-0ca5-4a94-92cd-7bc2316b6dcf', $q$Can AI tools like ChatGPT access Breakcold data?$q$, $q$Yes, Breakcold supports the Model Context Protocol (MCP), allowing Claude, ChatGPT, and other AI agents to read and update CRM records.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('cc05431a-0ca5-4a94-92cd-7bc2316b6dcf', $q$What channels does Breakcold support?$q$, $q$Breakcold syncs email, LinkedIn, WhatsApp, Telegram, and Instagram conversations into a single CRM inbox.$q$, 3);
