INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('298926b4-3ab4-4ee9-ae5b-9ee1b3900150', $q$Unified sales, marketing, and support$q$, $q$Run sales playbooks, marketing campaigns, and help desk SLAs from one CRM.$q$, $q$Growing businesses across industries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('298926b4-3ab4-4ee9-ae5b-9ee1b3900150', $q$AI-assisted deal management$q$, $q$Use predictive lead/deal scoring and AI-generated email drafts to prioritize follow-up.$q$, $q$Sales teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('298926b4-3ab4-4ee9-ae5b-9ee1b3900150', $q$One Growth$q$, $q$$12/user/month (annual) / $15 (monthly)$q$, $q$annual$q$, $q$["Core CRM modules"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('298926b4-3ab4-4ee9-ae5b-9ee1b3900150', $q$One Professional$q$, $q$$30/user/month (annual) / $42 (monthly)$q$, $q$annual$q$, $q$["Expanded sales, marketing, and help desk features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('298926b4-3ab4-4ee9-ae5b-9ee1b3900150', $q$One Enterprise$q$, $q$$42/user/month (annual) / $58 (monthly)$q$, $q$annual$q$, $q$["Advanced customization and automation"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('298926b4-3ab4-4ee9-ae5b-9ee1b3900150', $q$overview$q$, $q$What is Vtiger?$q$, 2, ARRAY[$q$Vtiger is a CRM platform with roots dating to 2004 as an open-source project, now offering both a cloud SaaS product and an open-source CRM edition.$q$, $q$It unifies sales, marketing, and help desk modules with AI features such as predictive lead and deal scoring, deal forecasting, and AI-generated email drafts, and it offers a free Pilot edition alongside paid One Growth, One Professional, and One Enterprise plans.$q$]::text[], 0);
