INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Does Kommo offer a free trial?$q$, $q$Yes, a 14-day free trial with full feature access and 10GB storage is available, with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$How much does Kommo cost?$q$, $q$Plans start at $15/user/month (Base) up to $45/user/month (Pro), with custom Enterprise pricing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$What channels does Kommo support?$q$, $q$Kommo unifies WhatsApp, Instagram, TikTok, Facebook, and Telegram conversations into one inbox.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Does Kommo have AI features?$q$, $q$Yes, it includes AI reply suggestions, AI task suggestions, and AI agents that scale in number by plan tier.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Messaging-first sales$q$, $q$Manage leads that come in primarily through WhatsApp, Instagram, or Telegram.$q$, $q$Sales teams selling via chat apps$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Automated lead response$q$, $q$Use Salesbot and 24/7 AI reply to instantly respond to incoming leads outside business hours.$q$, $q$Small to enterprise sales teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Base$q$, $q$$15/user/month$q$, NULL, $q$["Core CRM workspace","sales pipelines","unified inbox","AI reply suggestions","2,500 leads per user","1 WhatsApp number and Instagram account"]$q$::jsonb, 0);
