INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["SSO","enterprise-grade security","priority support","dedicated account manager"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5e37344-4c0e-4962-b411-76bbbd950cbd', $q$overview$q$, $q$What is Kommo?$q$, 2, ARRAY[$q$Kommo is a CRM built around messaging channels, unifying WhatsApp, Instagram, TikTok, Facebook, and Telegram conversations into a single inbox and sales pipeline.$q$, $q$It layers AI on top of that inbox with Salesbot automation, AI reply suggestions, AI-driven pipeline movement, and appointment scheduling, with the number of usable AI agents scaling by plan tier.$q$]::text[], 0);
