INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('27104aee-384b-47e0-8d77-8ae9c9dbfe01', $q$overview$q$, $q$What is Daylite?$q$, 2, ARRAY[$q$Daylite is a CRM and business management app built specifically for Mac, iPhone, and iPad. It consolidates contacts, email, calendar, tasks, notes, and a sales pipeline into one connected system.$q$, $q$Every email, meeting, and task is automatically linked to the relevant contact, project, or opportunity, giving a searchable history without switching between separate apps.$q$]::text[], 0);
