INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$What integrations does Userlist offer?$q$, $q$70+ integrations including Slack, HubSpot, Salesforce, Stripe, and Zapier, plus webhooks.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Lifecycle email automation$q$, $q$Build onboarding, trial-conversion, and retention journeys triggered by product usage.$q$, $q$B2B SaaS teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Account-based messaging$q$, $q$Segment and message at the company level when multiple users belong to one account.$q$, $q$SaaS teams with team/account plans$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Basic$q$, NULL, $q$monthly$q$, $q$["Up to 10,000 users included, then $10/month per additional 1,000 users","Marketing and lifecycle email","In-app messages","20 custom properties and 20 custom events","5 team seats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Professional$q$, NULL, $q$monthly$q$, $q$["Up to 10,000 users included, then $12/month per additional 1,000 users","A/B split testing","Conversion goals","50 custom properties, unlimited custom events","10 team seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$Enterprise$q$, NULL, NULL, $q$["Custom message limits","Custom integration support","Dedicated account manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$overview$q$, $q$What is Userlist?$q$, 2, ARRAY[$q$Userlist is an email marketing automation platform built specifically for SaaS companies. It lets teams build visual, multi-step customer journeys that combine lifecycle email, transactional email, and in-app messages.$q$, $q$Unlike generic email tools, Userlist models many-to-many relationships between users and companies, so messaging can be targeted at the account level rather than just individual contacts.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', $q$who-its-for$q$, $q$Who Userlist is for$q$, 2, ARRAY[$q$Userlist is aimed at growing B2B SaaS companies that need behavior-driven onboarding, retention, and upsell messaging tied to product usage data.$q$]::text[], 1);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95a1cd47-8a75-47d2-b10b-b9d86a58c71c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
