INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Cross-client email editor$q$, $q$Email design tool built for consistent rendering across email clients.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Lifecycle workflows$q$, $q$Automation builder with triggers, timers, and branching/conditional logic.$q$, 1);
