INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Permanent free plan for up to 1,000 contacts and 4,000 sends/month, no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Transactional email is included at no extra charge on paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$No per-seat charges, so teams can add users without added cost$q$, 2);
