INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Is there a free plan?$q$, $q$Yes, Loops offers a free plan for up to 1,000 subscribed contacts and about 4,000 sends per month, no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Does Loops charge per team seat?$q$, $q$No, Loops does not charge for additional team seats on any plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Is transactional email included?$q$, $q$Yes, transactional email sending is included at no additional charge on paid plans.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$What integrations does Loops support?$q$, $q$Supabase, Clerk, Zapier, Framer, Make, Segment, Webflow, Bubble, Stripe, PostHog, and Auth0, plus webhooks.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Unified SaaS email sending$q$, $q$Send marketing campaigns, lifecycle emails, and transactional messages from a single platform.$q$, $q$SaaS teams$q$, 0);
