INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["Up to 1,000 subscribed contacts","Up to ~4,000 sends/month","All features included","Loops branding footer"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$overview$q$, $q$What is Loops?$q$, 2, ARRAY[$q$Loops is an email platform for SaaS companies that combines product, marketing, and transactional email in a single tool, using contact-based rather than send-based pricing.$q$, $q$It provides a lifecycle workflow builder with triggers, timers, and branching logic, alongside a developer API and npm package for programmatic sending.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$who-its-for$q$, $q$Who Loops is for$q$, 2, ARRAY[$q$Loops targets SaaS teams and technical founders who want marketing and transactional email managed together, with direct access to product/usage data for segmentation.$q$]::text[], 1);
