INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d64e1be3-9d5e-44d1-8dab-25f1fd7f0d4c', $q$Can AI agents use Resend?$q$, $q$Yes, Resend provides an MCP server for integration with AI clients such as Cursor and Claude, and plans include a monthly allotment of AI credits.$q$, 3);
