INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$What is Maropost?$q$, $q$A unified commerce platform combining storefronts, inventory, marketing automation, POS, and customer service for mid-market ecommerce brands.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Does Maropost offer a free trial?$q$, $q$Yes, a free trial is available via the site's free-trial page, along with demo bookings.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$What ecommerce platforms does Maropost integrate with?$q$, $q$Pre-built integrations include Shopify, Stripe, Salesforce, Meta, Google Analytics, ClickBank, and Zapier, plus open APIs.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Does Maropost use AI?$q$, $q$Yes, the platform includes AI-driven insights, an AI chatbot for support, and Da Vinci AI for predictive intelligence and workflow automation.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Cross-channel marketing automation$q$, $q$Retailers run coordinated email, SMS, and social campaigns from the Marketing Cloud.$q$, $q$Mid-market ecommerce marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Unified retail and ecommerce operations$q$, $q$Brands manage storefronts, POS, and inventory together instead of stitching together separate systems.$q$, $q$Mid-market retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$AI-assisted merchandising$q$, $q$Merchandisers use AI-driven search and recommendations to personalize the shopping experience.$q$, $q$Ecommerce merchandising teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$overview$q$, $q$What is Maropost?$q$, 2, ARRAY[$q$Maropost is a unified commerce platform that brings storefronts, inventory, fulfillment, POS, and customer service together with its Marketing Cloud for cross-channel campaigns.$q$, $q$It targets mid-market ecommerce brands and retailers with roughly $20 million to $200 million in revenue, and includes AI-driven tools such as Da Vinci AI for predictive intelligence.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$who-its-for$q$, $q$Who Maropost is for$q$, 2, ARRAY[$q$Maropost is built for mid-market retail and ecommerce brands that need marketing automation connected to storefront, inventory, and POS data rather than a standalone email tool.$q$]::text[], 1);
