INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Visual journey builder$q$, $q$Design multi-step, multi-channel campaigns visually.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Multi-channel messaging$q$, $q$Send email, SMS, and iOS/Android push notifications from one platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$A/B testing$q$, $q$Test campaign variants across channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Data-warehouse segmentation$q$, $q$Segment users via API or direct SQL connections to warehouses like Snowflake and BigQuery.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Drag-and-drop templates$q$, $q$Build emails with a drag-and-drop template builder.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Broad integrations$q$, $q$Connect to Segment, Salesforce, Google Analytics, Twilio, and reverse ETL tools like Census and Hightouch.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Segmentation can be driven directly from a SQL data warehouse (Snowflake, BigQuery, Redshift), not just imported lists$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$14-day free trial with no credit card required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Broad integration list including reverse ETL tools (Census, Hightouch)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$99.99% uptime and a 4.3-star G2 rating cited on the site$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$No free plan, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Entry-level Starter plan ($54/month) is pricier than many basic email tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Professional plan pricing is custom/usage-based and not listed publicly$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Starter plan support is limited to 24/5, with 24/7 support reserved for Professional$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Does Vero offer a free trial?$q$, $q$Yes, a 14-day free trial is available with no credit card required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$What channels can Vero send messages through?$q$, $q$Email, SMS, and push notifications for iOS and Android.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$How much does Vero cost?$q$, $q$The Starter plan is $54/month ($49/month billed annually) for 5,000 profiles and 10,000 emails/month; the Professional plan is custom-priced based on usage.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Can Vero segment users from a data warehouse?$q$, $q$Yes, it supports segmentation via direct SQL connections to warehouses like Snowflake, BigQuery, and Redshift.$q$, 3);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Product-led lifecycle messaging$q$, $q$Product teams trigger onboarding and engagement emails, SMS, and push based on in-app behavior.$q$, $q$Product-led SaaS teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Data-warehouse-driven segmentation$q$, $q$Teams with a Snowflake or BigQuery warehouse segment users directly via SQL instead of syncing static lists.$q$, $q$Data and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Multi-channel campaign testing$q$, $q$Marketers A/B test messaging across email, SMS, and push from one journey builder.$q$, $q$Marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Starter$q$, $q$$54/month ($49/month billed annually)$q$, $q$monthly$q$, $q$["5,000 user profiles","10,000 emails/month","20,000 push messages/month","160,000 tracked events/month","Automated workflows and newsletters","Transactional emails","A/B testing","Unlimited team members","24/5 email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$Professional$q$, $q$Custom (usage-based)$q$, NULL, $q$["Custom profile/email/push/SMS volumes","All Starter features","Priority support","Dedicated customer success manager","24/7 priority support with live chat"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('707ba9cc-b9cc-4702-a3bc-db7861d4e8eb', $q$overview$q$, $q$What is Vero?$q$, 2, ARRAY[$q$Vero is a customer engagement platform that lets teams send personalized email, SMS, and push notifications from a single visual journey builder.$q$, $q$It integrates directly with data warehouses like Snowflake and BigQuery for segmentation, in addition to tools such as Segment, Salesforce, and Twilio.$q$]::text[], 0);
