INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('945d46de-1541-423b-ad90-a8381853daad', $q$overview$q$, $q$What is All in One SEO?$q$, 2, ARRAY[$q$All in One SEO (AIOSEO) is a WordPress plugin that combines on-page optimization (TruSEO checklists), automated technical SEO (sitemaps, schema, 404 handling), and an AI Assistant for content and image generation.$q$, $q$Paid tiers scale from a single site up to 100 sites, adding features like Link Assistant, advanced redirects, and client management as you move up.$q$]::text[], 0);
